512:     private DataInputStatus emitNextNotReading(DataOutput<OUT> output) throws Exception {
513:         switch (operatingMode) {
514:             case OUTPUT_NOT_INITIALIZED:
515:                 if (watermarkAlignmentParams.isEnabled()) {
516:                     // Only wrap the output when watermark alignment is enabled, as otherwise this
517:                     // introduces a small performance regression (probably because of an extra
518:                     // virtual call)
519:                     processingTimeService.scheduleWithFixedDelay(
520:                             time -> emitLatestWatermark(),
521:                             watermarkAlignmentParams.getUpdateInterval(),
522:                             watermarkAlignmentParams.getUpdateInterval());
523:                 }
524:                 initializeMainOutput(output);
525:                 return convertToInternalStatus(sourceReader.pollNext(currentMainOutput));
526:             case SOURCE_STOPPED:
527:                 this.operatingMode = OperatingMode.DATA_FINISHED;
528:                 sourceMetricGroup.idlingStarted();
529:                 return DataInputStatus.STOPPED;
530:             case SOURCE_DRAINED:
531:                 this.operatingMode = OperatingMode.DATA_FINISHED;
532:                 sourceMetricGroup.idlingStarted();
533:                 return DataInputStatus.END_OF_DATA;
534:             case DATA_FINISHED:
535:                 if (watermarkAlignmentParams.isEnabled()) {
536:                     latestWatermark = Watermark.MAX_WATERMARK.getTimestamp();
537:                     emitLatestWatermark();
538:                 }
539:                 sourceMetricGroup.idlingStarted();
540:                 return DataInputStatus.END_OF_INPUT;
541:             case WAITING_FOR_ALIGNMENT:
542:                 checkState(!waitingForAlignmentFuture.isDone());
543:                 checkState(shouldWaitForAlignment());
544:                 return convertToInternalStatus(InputStatus.NOTHING_AVAILABLE);
545:             case READING:
546:             default:
547:                 throw new IllegalStateException("Unknown operating mode: " + operatingMode);
548:         }
